// Parse Huawei SmartLogger 3000A power data
const data = {};
const buffer = msg.payload;

if (buffer && buffer.length >= 40) {
    // Parse according to register map
    data.active_power = (buffer.readInt32BE(0) / 1000).toFixed(2); // kW
    data.reactive_power = (buffer.readInt32BE(4) / 1000).toFixed(2); // kVar
    data.power_factor = (buffer.readInt16BE(8) / 1000).toFixed(3);
    data.phase_a_voltage = (buffer.readUInt16BE(10) / 10).toFixed(1); // V
    data.phase_b_voltage = (buffer.readUInt16BE(12) / 10).toFixed(1); // V
    data.phase_c_voltage = (buffer.readUInt16BE(14) / 10).toFixed(1); // V
    data.phase_a_current = (buffer.readInt16BE(16) / 100).toFixed(2); // A
    data.phase_b_current = (buffer.readInt16BE(18) / 100).toFixed(2); // A  
    data.phase_c_current = (buffer.readInt16BE(20) / 100).toFixed(2); // A
    data.frequency = (buffer.readUInt16BE(42) / 100).toFixed(2); // Hz
    data.status_1 = buffer.readUInt16BE(50);
    data.status_2 = buffer.readUInt16BE(52);
    data.alarm_1 = buffer.readUInt16BE(54);
    data.alarm_2 = buffer.readUInt16BE(56);

    data.timestamp = new Date().toISOString();
    data.device = 'Huawei SmartLogger 3000A';
}

msg.payload = data;
return msg;

// Parse SICES GC600 power data
const data = {};
const buffer = msg.payload;

if (buffer && buffer.length >= 60) {
    data.active_power = (buffer.readUInt32BE(0) / 1000).toFixed(2); // kW
    data.reactive_power = (buffer.readInt32BE(4) / 1000).toFixed(2); // kVar
    data.apparent_power = (buffer.readUInt32BE(8) / 1000).toFixed(2); // kVA
    data.power_factor = (buffer.readInt16BE(12) / 1000).toFixed(3);
    data.voltage_l1n = (buffer.readUInt16BE(20) / 10).toFixed(1); // V
    data.voltage_l2n = (buffer.readUInt16BE(22) / 10).toFixed(1); // V
    data.voltage_l3n = (buffer.readUInt16BE(24) / 10).toFixed(1); // V
    data.current_l1 = (buffer.readUInt16BE(40) / 100).toFixed(2); // A
    data.current_l2 = (buffer.readUInt16BE(42) / 100).toFixed(2); // A
    data.current_l3 = (buffer.readUInt16BE(44) / 100).toFixed(2); // A
    data.frequency = (buffer.readUInt16BE(60) / 100).toFixed(2); // Hz

    data.timestamp = new Date().toISOString();
    data.device = 'SICES GC600';
}

msg.payload = data;
return msg;

// Parse SICES MC200 grid monitoring data
const data = {};
const buffer = msg.payload;

if (buffer && buffer.length >= 150) {
    data.active_power_total = (buffer.readInt32BE(0) / 1000).toFixed(2); // kW (+import, -export)
    data.reactive_power_total = (buffer.readInt32BE(4) / 1000).toFixed(2); // kVar
    data.apparent_power_total = (buffer.readUInt32BE(8) / 1000).toFixed(2); // kVA
    data.power_factor_total = (buffer.readInt16BE(12) / 1000).toFixed(3);

    data.active_power_l1 = (buffer.readInt32BE(18) / 1000).toFixed(2); // kW
    data.active_power_l2 = (buffer.readInt32BE(22) / 1000).toFixed(2); // kW
    data.active_power_l3 = (buffer.readInt32BE(26) / 1000).toFixed(2); // kW

    data.voltage_l1n = (buffer.readUInt16BE(38) / 10).toFixed(1); // V
    data.voltage_l2n = (buffer.readUInt16BE(40) / 10).toFixed(1); // V
    data.voltage_l3n = (buffer.readUInt16BE(42) / 10).toFixed(1); // V

    data.current_l1 = (buffer.readUInt16BE(58) / 100).toFixed(2); // A
    data.current_l2 = (buffer.readUInt16BE(60) / 100).toFixed(2); // A
    data.current_l3 = (buffer.readUInt16BE(62) / 100).toFixed(2); // A

    data.frequency = (buffer.readUInt16BE(78) / 100).toFixed(2); // Hz

    data.import_energy_total = (buffer.readUInt32BE(98) / 100).toFixed(2); // kWh
    data.export_energy_total = (buffer.readUInt32BE(102) / 100).toFixed(2); // kWh

    data.phase_sequence = buffer.readUInt16BE(118);
    data.grid_status = buffer.readUInt16BE(120);
    data.protection_status = buffer.readUInt16BE(122);

    // Calculate import/export status
    data.is_importing = parseFloat(data.active_power_total) > 0;
    data.is_exporting = parseFloat(data.active_power_total) < 0;
    data.export_power = data.is_exporting ? Math.abs(parseFloat(data.active_power_total)) : 0;
    data.import_power = data.is_importing ? parseFloat(data.active_power_total) : 0;

    data.timestamp = new Date().toISOString();
    data.device = 'SICES MC200';
}

msg.payload = data;
return msg;

// Consolidate all device data
const devices = global.get('devices') || {};
const deviceName = msg.payload.device;

if (deviceName) {
    devices[deviceName] = msg.payload;
    global.set('devices', devices);

    // Send consolidated data every 5 seconds
    const lastSent = global.get('lastDataSent') || 0;
    const now = Date.now();

    if (now - lastSent > 5000) {
        global.set('lastDataSent', now);
        msg.payload = {
            timestamp: new Date().toISOString(),
            devices: devices,
            consolidated: true
        };
        return msg;
    }
}

return null;

// Monitor Huawei inverter status and alarms
const data = msg.payload;
const alarms = [];

if (data.alarm_1 > 0 || data.alarm_2 > 0) {
    alarms.push({
        device: 'Huawei SmartLogger 3000A',
        type: 'alarm',
        alarm_1: data.alarm_1,
        alarm_2: data.alarm_2,
        timestamp: data.timestamp
    });
}

if (alarms.length > 0) {
    msg.payload = alarms;
    return msg;
}

return null;

// Monitor GC600 genset status
const data = msg.payload;
const status = [];

// Add genset operational status monitoring logic here
status.push({
    device: 'SICES GC600',
    active_power: data.active_power,
    frequency: data.frequency,
    operational: parseFloat(data.active_power) > 0,
    timestamp: data.timestamp
});

msg.payload = status;
return msg;

// Monitor MC200 grid status and protection
const data = msg.payload;
const status = [];

status.push({
    device: 'SICES MC200',
    grid_status: data.grid_status,
    protection_status: data.protection_status,
    phase_sequence: data.phase_sequence,
    import_export_status: {
        importing: data.is_importing,
        exporting: data.is_exporting,
        import_power: data.import_power,
        export_power: data.export_power
    },
    timestamp: data.timestamp
});

msg.payload = status;
return msg;

// Zero export to grid control logic
const data = msg.payload;
const zeroExportThreshold = global.get('zeroExportThreshold') || 50; // Watts
const exportPower = parseFloat(data.export_power) || 0;

if (exportPower > zeroExportThreshold) {
    // Trigger PV curtailment
    const curtailmentCommand = {
        device: 'Huawei SmartLogger 3000A',
        action: 'curtail_power',
        target_power_limit: Math.max(0, 100 - (exportPower / 10)), // Reduce by export amount
        reason: 'zero_export_protection',
        timestamp: new Date().toISOString()
    };

    msg.payload = curtailmentCommand;
    return msg;
}

return null;
